# -*- coding: utf-8 -*-
"""Clawd Desktop — 완전 단독 .exe (Edge WebView2)"""
import base64, sys, os, tempfile

_HTML_B64 = ""
_ICON_B64  = ""

def get_html():
    return base64.b64decode(_HTML_B64).decode("utf-8")

def extract_icon():
    try:
        tmp = tempfile.NamedTemporaryFile(suffix=".png", delete=False)
        tmp.write(base64.b64decode(_ICON_B64))
        tmp.close()
        return tmp.name
    except Exception:
        return None

def main():
    import webview
    extract_icon()
    window = webview.create_window(
        title="Clawd",
        html=get_html(),
        width=1280,
        height=800,
        min_size=(800, 600),
        background_color="#1a1a2e",
        text_select=False,
    )
    storage = os.path.join(os.path.expanduser("~"), ".clawd")
    os.makedirs(storage, exist_ok=True)
    webview.start(
        gui="edgechromium",
        debug=False,
        private_mode=False,
        storage_path=storage,
    )

if __name__ == "__main__":
    main()
